public int minEatingSpeed(int[] piles, int h) {
    int left = 1, right = 1;
    for (int pile : piles)
        right = Math.max(right, pile);
    while (left < right) {
        int mid = left + (right - left) / 2;
        int totalHours = 0;
        for (int pile : piles)
            totalHours += (pile + mid - 1) / mid;
        if (totalHours > h)
            left = mid + 1;
        else
            right = mid;
    }
    return left;
}
```

